<template>
  <view class="login-container">
    <!-- 使用正确的图片路径 -->
    <image class="logo" src="/static/images/logo.png"></image>
    <view class="title">中国手工文化平台</view>
    
    <view class="form-group">
      <input 
        v-model="formData.user_name"
        placeholder="请输入用户名/邮箱" 
        class="input" 
        type="text"
      />
    </view>
    
    <view class="form-group">
      <input 
        v-model="formData.password"
        placeholder="请输入密码" 
        class="input" 
        :type="showPassword ? 'text' : 'password'"
      />
      <text class="password-toggle" @click="togglePassword">
        {{ showPassword ? '隐藏' : '显示' }}
      </text>
    </view>
    
    <button class="login-btn" @click="handleLogin" :loading="loading">登录</button>
    
    <view class="footer">
      <navigator url="/pages/register/register" class="link">没有账号？立即注册</navigator>
      <view class="link" @click="handleError">忘记密码</view>
    </view>
  </view>
</template>

<script>
// 导入请求方法 - 注意路径
import { post } from '@/utils/request.js'

export default {
  data() {
    return {
      formData: {
        user_name: '',
        password: ''
      },
      loading: false,
      showPassword: false
    }
  },
  methods: {
    togglePassword() {
      this.showPassword = !this.showPassword
    },
    
    async handleLogin() {
      if (this.loading) return
      
      // 表单验证
      if (!this.formData.user_name.trim()) {
        uni.showToast({
          title: '请输入用户名/邮箱',
          icon: 'none'
        })
        return
      }
      
      if (!this.formData.password.trim()) {
        uni.showToast({
          title: '请输入密码',
          icon: 'none'
        })
        return
      }
      
      this.loading = true
      
      try {
        const res = await post('/user/login', {
          account: this.formData.user_name,
          password: this.formData.password
        })
        
        console.log('登录响应:', res)
        
        if (res.success) {
          console.log("登录成功")
          console.log("用户ID:", res.userInfo?.user_id)
          
          uni.showToast({
            title: res.message || '登录成功',
            icon: 'success'
          })
          
          // 存储用户信息
          uni.setStorageSync('user_name', res.user_name)
          uni.setStorageSync('userInfo', {
            userId: res.userInfo?.user_id,
            userName: res.userInfo?.user_name,
            email: res.userInfo?.email
          })
          
          // 延迟跳转
          setTimeout(() => {
            // uni.switchTab 用于跳转到 tabBar 页面
            // uni.navigateTo 用于普通页面跳转
            uni.switchTab({
              url: '/pages/home/home',
              success: () => console.log('跳转成功！'),
              fail: (err) => console.log('失败原因：', err)
            })
          }, 1500)
          
        } else {
          uni.showToast({
            title: res.message || '登录失败',
            icon: 'none'
          })
        }
      } catch (err) {
        console.error('登录请求异常:', err)
        uni.showToast({
          title: '网络错误，请稍后重试',
          icon: 'none'
        })
      } finally {
        this.loading = false
      }
    },
    
    handleError() {
      uni.showModal({
        title: '提示',
        content: '更多功能正在开发中，敬请期待',
        showCancel: false,
        confirmText: '我知道了',
        success: (res) => {
          if (res.confirm) {
            console.log('用户点击了我知道了')
          }
        }
      })
    }
  }
}
</script>

